import psycopg2
from psycopg2 import sql, extensions

def connect_to_db():
    conn = None
    try:
        conn = psycopg2.connect(host="localhost", database="testDB", user="postgres", password="password")
    except (Exception, psycopg2.DatabaseError) as error:
        print(error)
    return conn

def search_users(username=None, email=None, role=None, status=None):
    
    conditions = []
    params = []
    
    if username is not None:
        conditions.append("username = %s")
        params.append(username)
        
    if email is not None:
        conditions.append("email = %s")
        params.append(email)

    if role is not None:
        conditions.append("role = %s")
        params.append(role)

    if status is not None:
        conditions.append("status = %s")
        params.append(status)
    
    if len(conditions) == 0:
        return "No search criteria provided"
        
    conn = connect_to_db()
    cur = conn.cursor()

    query = sql.SQL("SELECT * FROM users WHERE {}").format(sql.SQL(' AND ').join([sql.SQL(condition) for condition in conditions]))
    
    cur.execute(query, params)
    rows = cur.fetchall()
  
    return rows